import { useEffect, useState } from "react";

export default function useGetSingleAPOD(today) {
  const [image, setImage] = useState(null);

  let key = 'hK9L5EdqbSfX3VLvK84iefSH0yV3te6DYTv1JLG4';
  const url = `https://api.nasa.gov/planetary/apod?api_key=${key}`;

  useEffect(() => {    
    
    // const getPhoto = async () => {
    //   const response = await fetch('http://localhost:3001/api/single-img', {
    //     method: 'GET'
    //   })
    //   .then(response => response.json())
    //   .then(data => {
    //     setImage(data);
    //     localStorage.setItem('currentDay', JSON.stringify(data));
    //   });
    // };

    const getPhoto = () => {
      const response = fetch('http://localhost:3001/', {
        method: 'GET'
      })
      .then(response => response.json())
      .then(data => {
        setImage(data);
        localStorage.setItem('currentDay', JSON.stringify(data));
      });
    };

    if (localStorage.getItem('currentDay') === null) {
      getPhoto();
    } else {
      const data = localStorage.getItem('currentDay');
      const newData = JSON.parse(data);
      if (newData.date !== today) {
        getPhoto();
      } else {
        setImage(newData);
      }
      
    }

  }, []);

  return image;
}
